1	// pixel-art-scaler.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { scalePixelArt } from "./pixel-art-scaler.js";
4	
5	describe("Pixel Art Scaler", () => {
6	  it("should return an empty image when given an empty image with scale 1", () => {
7	    expect(scalePixelArt("", 1)).toBe("");
8	  });
9	  it("should return an exact copy of a single-pixel image when scale is 1", () => {
10	    expect(scalePixelArt("X", 1)).toBe("X");
11	  });
12	  it("should return an exact copy of a multi-pixel image when scale is 1", () => {
13	    expect(scalePixelArt("AB\nCD", 1)).toBe("AB\nCD");
14	  });
15	  it("should replicate a single pixel horizontally and vertically when scale is 2", () => {
16	    expect(scalePixelArt("X", 2)).toBe("XX\nXX");
17	  });
18	  it("should scale a single-row image by replicating each pixel horizontally", () => {
19	    expect(scalePixelArt("AB", 2)).toBe("AABB\nAABB");
20	  });
21	  it("should scale a single-column image by replicating each row vertically", () => {
22	    expect(scalePixelArt("A\nB", 2)).toBe("AA\nAA\nBB\nBB");
23	  });
24	  it("should scale a multi-row multi-column image preserving character values", () => {
25	    expect(scalePixelArt("AB\nCD", 2)).toBe("AABB\nAABB\nCCDD\nCCDD");
26	    expect(scalePixelArt("A#\n*Z", 3)).toBe("AAA###\nAAA###\nAAA###\n***ZZZ\n***ZZZ\n***ZZZ");
27	  });
28	  it("should return an empty image when given an empty image with scale greater than 1", () => {
29	    expect(scalePixelArt("", 5)).toBe("");
30	  });
31	});
32

1	export const scalePixelArt = (image: string, scale: number): string => {
2	  if (image === "") return "";
3	  return image
4	    .split("\n")
5	    .map((row) => [...row].map((char) => char.repeat(scale)).join(""))
6	    .flatMap((scaledRow) => Array(scale).fill(scaledRow))
7	    .join("\n");
8	};
